import json, sys, csv, io, statistics
args = json.load(sys.stdin)
csv_data = args.get('csv_data', '')
reader = csv.DictReader(io.StringIO(csv_data.strip()))
rows = list(reader)
stats = {}
if rows:
    for col in rows[0].keys():
        vals_raw = [r[col].strip() for r in rows if r.get(col, '').strip()]
        try:
            vals = [float(v) for v in vals_raw]
            stats[col] = {
                'count': len(vals),
                'mean': round(statistics.mean(vals), 4),
                'min': min(vals),
                'max': max(vals),
                'total': round(sum(vals), 4)
            }
        except (ValueError, TypeError):
            stats[col] = {'type': 'string', 'unique': len(set(vals_raw))}
print(json.dumps({'ok': True, 'data': {'stats': stats, 'row_count': len(rows)}}))
